import re
from collections import Counter
from flask import Flask, request, jsonify
from sklearn.linear_model import LogisticRegression
from sklearn.model_selection import train_test_split
import numpy as np

app = Flask(__name__)

# --- Model Training (simplified, usually done offline) ---
# Sample data for training
# A real system would use a much larger, diverse dataset
corpus = [
    ("Send money urgently to my account for inheritance.", 1),
    ("You have won a lottery, click here to claim your prize.", 1),
    ("Hello, how are you doing today?", 0),
    ("Please confirm your shipping address for your order.", 0),
    ("Your package delivery has been delayed, check status here.", 1),
    ("Meeting reminder: Tomorrow at 10 AM in conference room.", 0),
    ("Get rich quick scheme, invest now!", 1),
    ("Productivity tips for a successful week.", 0),
    ("Unsubscribe from this list to stop receiving emails.", 1),
    ("Regarding the project proposal, please review the attached document.", 0),
    ("Claim your free gift card now!", 1),
    ("Daily news updates from your favorite sources.", 0),
    ("Your account has been compromised, verify your details.", 1),
    ("Important security alert for your online banking.", 1),
    ("Invoice for services rendered last month.", 0),
    ("Special offer just for you, don't miss out!", 1),
    ("Customer support inquiry response.", 0),
    ("We need your help to fight climate change.", 0),
    ("Viagra for sale, cheap prices!", 1),
    ("Your order has been shipped and is on its way.", 0),
]

# Vocabulary builder
def build_vocabulary(corpus_data):
    all_words = Counter()
    for text, _ in corpus_data:
        words = re.findall(r'\b\w+\b', text.lower())
        all_words.update(words)
    # Keep top N words, or filter by frequency
    return {word: i for i, (word, count) in enumerate(all_words.most_common(500))} # Top 500 words

vocabulary = build_vocabulary(corpus)

# Feature extraction: simple bag-of-words (word frequency)
def extract_features(text, vocabulary):
    features = np.zeros(len(vocabulary))
    words = re.findall(r'\b\w+\b', text.lower())
    for word in words:
        if word in vocabulary:
            features[vocabulary[word]] += 1
    return features

# Prepare dataset for training
X = np.array([extract_features(text, vocabulary) for text, _ in corpus])
y = np.array([label for _, label in corpus])

# Train a Logistic Regression model
model = LogisticRegression(solver='liblinear', random_state=42)
model.fit(X, y)

# --- API Endpoints ---
@app.route('/predict_spam', methods=['POST'])
def predict_spam():
    if not request.is_json:
        return jsonify({"error": "Request must be JSON"}), 400

    data = request.get_json()
    email_text = data.get('email_text')

    if not email_text:
        return jsonify({"error": "email_text field is required"}), 400

    try:
        features = extract_features(email_text, vocabulary)
        # Reshape for single prediction
        features_reshaped = features.reshape(1, -1)
        
        # Predict probability of being spam (class 1)
        spam_probability = model.predict_proba(features_reshaped)[0][1]
        
        return jsonify({
            "email_text": email_text,
            "spam_probability": spam_probability
        })
    except Exception as e:
        return jsonify({"error": str(e)}), 500

if __name__ == '__main__':
    # For a production environment, use a production WSGI server like Gunicorn
    app.run(debug=True, host='0.0.0.0', port=5000)